  ('judicial-57f41407-moex-00653', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '適用下列何種訴訟程序之事件，提起第三審上訴應經原裁判法院許可？', '["適用通常訴訟程序之清償借款事件", "適用小額訴訟程序之給付貨款事件", "適用簡易訴訟程序之給付票款事件", "適用通常訴訟程序之勞動事件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00654', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於小額訴訟程序，下列敘述何者錯誤？', '["當事人一造為法人，以預定用於同類契約之條款，就關於一定法律關係而生之訴訟，與為自然人之 他造簽訂書面合意定第一審管轄法院，法院不得據以定管轄法院", "得於夜間進行訴訟程序", "經兩造同意得不調查證據", "當事人無論是否向法院陳明就其餘額不另起訴請求，均得為適用小額訴訟程序而為一部請求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00655', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於民事訴訟程序委任律師為訴訟代理人，下列敘述何者正確？', '["對於通常訴訟程序第二審法院所為裁定，向最高法院提起抗告時，抗告人應委任律師為訴訟代理人", "對於第二審判決提起上訴，而向最高法院聲請訴訟救助時，應委任律師為訴訟代理人", "第三審上訴事件行言詞辯論程序時，兩造均應委任律師為訴訟代理人", "對於最高法院之確定裁定聲請再審時，均應委任律師為訴訟代理人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00656', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲起訴請求乙遷讓返還甲所有之 A 屋，經第一審法院裁定：①核定訴訟標的價額為新臺幣（下同）', '["甲應於收受該裁定之翌日起7日內繳納第一審裁判費2萬元，逾期駁回起訴。甲不服該 裁定，全部提起抗告。下列敘述何者正確？", "第一審法院關於核定訴訟標的價額之裁定，為訴訟程序進行中所為之裁定，不得抗告", "第一審法院關於命甲繳納第一審裁判費之裁定，事涉甲起訴合法與否，影響甲之程序基本權，應得 抗告", "如抗告法院駁回甲關於第一審法院核定訴訟標的價額裁定之抗告，甲得以其適用法規顯有錯誤為理 由，再為抗告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00657', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於再審期間，下列敘述何者正確？', '["為不變期間", "為通常法定期間", "為裁定期間", "如有重大理由，法院得以裁定伸長或縮短之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00658', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於第三人撤銷之訴之原告適格，下列敘述何者正確？', '["前訴訟程序之原告", "前訴訟程序之被告", "前訴訟程序之參加人", "未參加前訴訟而有法律上利害關係之第三人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00659', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於督促程序，下列敘述何者錯誤？', '["法院應訊問債務人後，就支付命令之聲請為裁定", "支付命令之送達應於外國為之者，不得行之", "支付命令之送達應依公示送達為之者，不得行之", "聲請人應為對待給付尚未履行者，不得行之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00660', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於聲請除權判決，下列敘述何者正確？', '["公示催告聲請人，原則上得於申報權利之期間已滿後3個月內，聲請為除權判決", "公示催告聲請人，不於第一次言詞辯論期日到場者，法院應依職權另定新期日", "公示催告聲請人，遲誤法院另定之新期日者，得於3個月內聲請法院更定新期日", "對於除權判決不服，得於判決送達後20日之不變期間內提起上訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00661', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '乙女與甲男離婚後，隨即與丙男結婚，嗣後乙女生下一子A，惟就A為甲或丙之子女一事，關係人間 尚有爭執。關於確定母再婚後所生子女生父之訴，下列敘述何者正確？', '["由A起訴時，應以甲、乙、丙為共同被告", "由乙女起訴時，應以甲與丙為共同被告", "由甲起訴時，應以乙、丙為共同被告", "由丙起訴時，應以甲、乙為共同被告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00662', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於家事事件法之調解程序，下列敘述何者錯誤？', '["當事人就分割遺產事件於法院成立調解時，與確定判決有同一之效力", "當事人於法院成立離婚之調解者，法院應依職權通知該管戶政機關辦理登記，否則不生離婚之效力", "法院得於家事事件之審理程序進行中依職權移付調解", "當事人兩造得合意聲請將相牽連之民事事件合併於家事事件而為調解 乙、刑事訴訟法部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
